    def new(self):
        """Cree et retourne une nouvelle instance depuis le fichier Glade.

        Returns:
            instance: Nouvelle instance de la classe.
        """
        self.hpMain = self.get_widget("hpMain")
        self.wMainWindow = self.builder.get_object("wMain")
